'use strict';

var getObjectType = require('./getObjectType.js');

function checkRendering(rendering, usage) {
    if (rendering === undefined || typeof rendering !== 'function') {
        throw new Error("The render function is not valid (received type ".concat(getObjectType.getObjectType(rendering), ").\n\n").concat(usage));
    }
}

exports.checkRendering = checkRendering;
